import { OrderRepository } from './orderRepository';

export class OrderService {
  constructor(private readonly orders: OrderRepository) {}

  async markShipped(orderId: string): Promise<void> {
    const order = await this.orders.findById(orderId);

    if (!order) {
      throw new Error(`Order not found: ${orderId}`);
    }

    if (order.status === 'cancelled') {
      throw new Error('Cancelled orders cannot be shipped');
    }

    await this.orders.updateStatus(orderId, 'shipped');
  }
}
```

When an order is marked shipped, notify the customer. We currently send notifications through email, but we may add SMS later. Add the feature while preserving domain boundaries.
